function [] = fPltInfV02(handle,info,numInf,fSize)%% Function Plot Information, ver.1%% [] = fPltInfV02(handle,info,numInf,fSize);% plots information%% handle: figure hundle% info: information in string cell% numInf: number of information to be plotted% fSize: font size%% used in% bellaCompAnglV06%% Written by Kei Nakamura% 2007/4/23 ver.1: created% 2013/5/14 ver.2: including font size%% mainhold off;plot(0);a = axis;d = (a(4)-a(3))/(numInf-1);for ii=1:numInf    posY = a(4)-(ii-1)*d;    text(a(1),posY,info{ii},'FontSize',fSize);endset(handle,'Visible','off')
